const response = $input.first().json;
const locations = response.locations || [];

return locations.map((loc) => {
  const cepRaw = String(loc.storefrontAddress?.postalCode || '');
  const cep = cepRaw.replace(/\D/g, '');

  return {
    json: {
      location: loc,
      cep,
    },
  };
});

const viaCepItems = $input.all();
const splitItems = $items('Split Locations');

const formattedLocations = viaCepItems.map((viaCepItem, index) => {
  const loc = splitItems[index]?.json?.location || {};
  const address = loc.storefrontAddress || {};
  const phone = loc.phoneNumbers?.primaryPhone || '';
  const additionalPhones = loc.phoneNumbers?.additionalPhones || [];
  const categories = loc.categories || {};
  const viaCepBairro = typeof viaCepItem.json?.bairro === 'string' ? viaCepItem.json.bairro : '';
  const viaCepErro = viaCepItem.json?.erro === true || viaCepItem.json?.erro === 'true' || Boolean(viaCepItem.json?.error);

  // Converter horários para formato mais simples
  const hours = {};
  if (loc.regularHours?.periods) {
    loc.regularHours.periods.forEach((period) => {
      const day = period.openDay?.toLowerCase() || 'unknown';
      const openHour = period.openTime?.hours || 0;
      const openMin = period.openTime?.minutes || 0;
      const closeHour = period.closeTime?.hours || 0;
      const closeMin = period.closeTime?.minutes || 0;

      hours[day] = {
        open: `${String(openHour).padStart(2, '0')}:${String(openMin).padStart(2, '0')}`,
        close: `${String(closeHour).padStart(2, '0')}:${String(closeMin).padStart(2, '0')}`,
      };
    });
  }

  // Extrair número e rua do addressLines
  const fullAddress = address.addressLines?.[0] || '';
  const neighborhood = !viaCepErro && viaCepBairro ? viaCepBairro : address.sublocality || '';

  return {
    // IDs de referência
    google_location_id: loc.name,
    google_place_id: loc.metadata?.placeId || '',
    google_maps_uri: loc.metadata?.mapsUri || '',

    // Info Básica
    name: loc.title || '',
    description: loc.profile?.description || '',

    // Contato
    phone_primary: phone,
    phone_additional: additionalPhones.join(', '),
    website: loc.websiteUri || '',

    // Endereço
    address_full: fullAddress,
    address_city: address.locality || '',
    address_state: address.administrativeArea || '',
    address_postal_code: address.postalCode || '',
    address_country: address.regionCode || 'BR',
    address_neighborhood: neighborhood,

    // Categorias
    category_primary: categories.primaryCategory?.displayName || '',
    categories_additional: (categories.additionalCategories || [])
      .map((c) => c.displayName)
      .filter(Boolean),

    // Horários formatados
    hours: hours,
  };
});

return [{
  json: {
    success: true,
    total: formattedLocations.length,
    locations: formattedLocations,
    timestamp: new Date().toISOString(),
  },
}];
